typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

Node* newNode(int data) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->data = data;
    n->left = n->right = NULL;
    return n;
}

Node* construct(int* pre, int* idx, int n, int min, int max) {
    if (*idx >= n) return NULL;
    int val = pre[*idx];
    if (val < min || val > max) return NULL;
    Node* root = newNode(val);
    (*idx)++;
    root->left = construct(pre, idx, n, min, val - 1);
    root->right = construct(pre, idx, n, val + 1, max);
    return root;
}

