import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int data;
        Node left, right;
        Node(int d) { data = d; }
    }

    static Node construct(int[] pre, int[] idx, int min, int max) {
        if (idx[0] >= pre.length) return null;
        int val = pre[idx[0]];
        if (val < min || val > max) return null;
        Node node = new Node(val);
        idx[0]++;
        node.left = construct(pre, idx, min, val - 1);
        node.right = construct(pre, idx, val + 1, max);
        return node;
    }

    static void levelOrder(Node root, StringBuilder sb) {
        if (root == null) return;
        Queue<Node> q = new ArrayDeque<>();
        q.add(root);
        while (!q.isEmpty()) {
            Node cur = q.poll();
            sb.append(cur.data).append(' ');
            if (cur.left != null) q.add(cur.left);
            if (cur.right != null) q.add(cur.right);
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] pre = new int[N];
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; ++i) pre[i] = Integer.parseInt(st.nextToken());
            int[] idx = {0};
            Node root = construct(pre, idx, Integer.MIN_VALUE, Integer.MAX_VALUE);
            levelOrder(root, out);
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

