import sys
from collections import deque

def construct(pre, idx, min_val, max_val):
    if idx[0] >= len(pre):
        return None
    val = pre[idx[0]]
    if val < min_val or val > max_val:
        return None
    node = (val, None, None)
    idx[0] += 1
    left = construct(pre, idx, min_val, val - 1)
    right = construct(pre, idx, val + 1, max_val)
    return (val, left, right)

def level_order(root, out):
    if not root:
        return
    q = deque([root])
    while q:
        val, left, right = q.popleft()
        out.append(str(val))
        out.append(' ')
        if left:
            q.append(left)
        if right:
            q.append(right)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    results = []
    for _ in range(T):
        N = int(next(it))
        pre = [int(next(it)) for _ in range(N)]
        idx = [0]
        root = construct(pre, idx, -10**9, 10**9)
        out = []
        level_order(root, out)
        results.append(''.join(out).strip())
    sys.stdout.write('\n'.join(results))

if __name__ == "__main__":
    solve()

